  "inlineSchema": "// 1. Database Connection \ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// 2. Roles (User lge types)\nenum UserRole {\n  ADMIN // Company Admin\n  MANAGER\n  TECHNICIAN\n  OCCUPANT\n}\n\n// 3. Tenant (Company / Organization)\nmodel Tenant {\n  id   String @id @default(uuid())\n  name String\n\n  // මෙන්න අපේ අලුත් Join Code එක 🔑\n  // මේකෙන් තමයි අලුත් Technician කෙනෙක්ට කොම්පැණිය හොයාගන්න ලේසි වෙන්නේ.\n  joinCode String @unique @default(cuid())\n\n  domain    String?  @unique // e.g., alpha.fms.com\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  users      User[]\n  assets     Asset[]\n  workOrders WorkOrder[]\n  parts      Part[]\n\n  @@index([createdAt])\n}\n\n// 4. Users table\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  firstName String\n  lastName  String\n  role      UserRole @default(OCCUPANT)\n\n  // Link to Tenant\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relation for Work Orders assigned to this user\n  assignedWorkOrders WorkOrder[] @relation(\"AssignedWorkOrders\")\n\n  @@index([tenantId])\n  @@index([role])\n  @@index([createdAt])\n}\n\n// 5. Asset Status\nenum AssetStatus {\n  ACTIVE\n  INACTIVE\n  MAINTENANCE\n  RETIRED\n}\n\n// 6. Assets (Inventory)\nmodel Asset {\n  id       String      @id @default(uuid())\n  name     String\n  category String\n  serialNo String?\n  status   AssetStatus @default(ACTIVE)\n\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  workOrders WorkOrder[]\n\n  @@unique([tenantId, serialNo])\n  @@index([tenantId])\n  @@index([status])\n  @@index([category])\n}\n\n// 7. Work Order Status\nenum WorkOrderStatus {\n  OPEN\n  IN_PROGRESS\n  ON_HOLD\n  COMPLETED\n  CANCELLED\n}\n\n// 8. Work Order Priority\nenum WorkOrderPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\n// 9. Work Orders \nmodel WorkOrder {\n  id          String            @id @default(uuid())\n  title       String\n  description String?\n  status      WorkOrderStatus   @default(OPEN)\n  priority    WorkOrderPriority @default(MEDIUM)\n\n  // Link to Asset\n  assetId String\n  asset   Asset  @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  // Link to Tenant\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  // Link to Assigned Technician\n  assignedToId String?\n  assignedTo   User?   @relation(\"AssignedWorkOrders\", fields: [assignedToId], references: [id])\n\n  // Completion Note (Written by Technician)\n  completionNote String?\n\n  // Parts used in this work order\n  parts WorkOrderPart[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId])\n  @@index([assetId])\n  @@index([status])\n  @@index([priority])\n  @@index([createdAt])\n  @@index([assignedToId])\n}\n\n// 10. Parts (Inventory & Spare Parts)\nmodel Part {\n  id         String @id @default(uuid())\n  name       String\n  partNumber String\n  stockLevel Int    @default(0)\n  minStock   Int    @default(10)\n  unitPrice  Float  @default(0.0)\n\n  // Link to Tenant\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  // Parts used in work orders\n  workOrderParts WorkOrderPart[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([tenantId, partNumber])\n  @@index([tenantId])\n  @@index([stockLevel])\n}\n\n// 11. Work Order Parts (Junction table for materials used)\nmodel WorkOrderPart {\n  id       String @id @default(uuid())\n  quantity Int\n\n  // Link to Work Order\n  workOrderId String\n  workOrder   WorkOrder @relation(fields: [workOrderId], references: [id], onDelete: Cascade)\n\n  // Link to Part\n  partId String\n  part   Part   @relation(fields: [partId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([workOrderId])\n  @@index([partId])\n}\n",
